import { useEffect, useMemo, useState } from 'react';
import { ArrowLeft, Copy, Eye, GripVertical, History, Image, Layers, Library, Monitor, Palette, Plus, Redo2, Save, Search, Send, Settings, Smartphone, Tablet, Trash2, Undo2, Upload } from 'lucide-react';
import { Link } from '../components/Router';
import { HomepageRenderer } from '../components/HomepageRenderer';
import { Badge, Button, EmptyState, LoadingState } from '../components/ui';
import { useBranding } from '../lib/branding';
import { defaultGlobalStyles, defaultSeo, designThemePresets, homepageStylePresets, makeSection, normalizeSections, pageTemplates, sectionLibrary, sectionTypeLabels, matchAllSectionsToTheme, matchSectionToTheme, validateHomepage, type HomepageBuilderResponse, type HomepageDraft, type HomepageItem, type HomepageMedia, type HomepageSection, type HomepageSectionLibraryEntry, type HomepageSectionType } from '../lib/homepage-builder';

type Panel = 'sections' | 'templates' | 'pages' | 'theme' | 'animations' | 'global' | 'media';
type Device = 'desktop' | 'tablet' | 'mobile';
type MediaAsset = { id: string; fileName: string; url?: string; visibility: 'public' | 'private'; altText?: string; mimeType?: string };
const emptyDraft: HomepageDraft = { sections: [], globalStyles: defaultGlobalStyles, seo: defaultSeo };
const api = async <T,>(url: string, init?: RequestInit): Promise<T> => { const r = await fetch(url, { credentials: 'include', cache: 'no-store', headers: { accept: 'application/json', ...(init?.body ? { 'content-type': 'application/json' } : {}) }, ...init }); const p = await r.json().catch(() => ({})); if (!r.ok) throw new Error(p.error || `Request failed (${r.status})`); return p as T; };

export function AdvancedHomepageBuilder({ initialData, canManage, reload }: { initialData?: HomepageBuilderResponse | null; canManage: boolean; reload?: () => Promise<void> }) {
  const branding = useBranding();
  const [data, setData] = useState<HomepageBuilderResponse | null>(initialData || null);
  const [loading, setLoading] = useState(!initialData);
  const [draft, setDraft] = useState<HomepageDraft>(initialData?.draft || emptyDraft);
  const [selectedId, setSelectedId] = useState(initialData?.draft?.sections?.[0]?.id || '');
  const [panel, setPanel] = useState<Panel>('sections');
  const [leftCollapsed, setLeftCollapsed] = useState(() => localStorage.getItem('homepageBuilderLeftCollapsed') === 'true');
  const [rightCollapsed, setRightCollapsed] = useState(false);
  const [presetBrowserOpen, setPresetBrowserOpen] = useState(false);
  const [device, setDevice] = useState<Device>('desktop');
  const [status, setStatus] = useState('Draft ready');
  const [dragId, setDragId] = useState('');
  const [sectionSearch, setSectionSearch] = useState('');
  const [sectionCategory, setSectionCategory] = useState('All');
  const [sectionGoal, setSectionGoal] = useState('All');
  const [sectionFilter, setSectionFilter] = useState('All');
  const [previewPreset, setPreviewPreset] = useState<HomepageSectionLibraryEntry | null>(null);
  const [history, setHistory] = useState<HomepageDraft[]>([]);
  const [future, setFuture] = useState<HomepageDraft[]>([]);
  const [media, setMedia] = useState<MediaAsset[]>([]);
  const validation = useMemo(() => validateHomepage(draft), [draft]);
  const selected = normalizeSections(draft.sections).find((section) => section.id === selectedId) || null;
  const library = useMemo(() => sectionLibrary(), []);
  const libraryCategories = useMemo(() => ['All', ...Array.from(new Set(library.map((entry) => entry.category)))], [library]);
  const libraryGoals = useMemo(() => ['All', ...Array.from(new Set(library.map((entry) => entry.goal)))], [library]);
  const premiumFilters = ['All','Animated','High Converting','Mobile First','Trust Builder','Past Work','Emergency Calls','SEO','Commercial','Residential'];
  const filteredLibrary = useMemo(() => { const q = sectionSearch.trim().toLowerCase(); return library.filter((entry) => { const categoryOk = sectionCategory === 'All' || entry.category === sectionCategory; const goalOk = sectionGoal === 'All' || entry.goal === sectionGoal; const filterOk = sectionFilter === 'All' || [entry.name, entry.description, entry.recommendedUseCase, entry.goal, entry.category, ...entry.tags, ...entry.variants].join(' ').toLowerCase().includes(sectionFilter.toLowerCase()); const haystack = [entry.name, entry.description, entry.recommendedUseCase, entry.goal, entry.category, ...entry.tags, ...entry.variants].join(' ').toLowerCase(); return categoryOk && goalOk && filterOk && (!q || haystack.includes(q)); }); }, [library, sectionSearch, sectionCategory, sectionGoal, sectionFilter]);
  const templates = useMemo(() => pageTemplates(branding), [branding.displayName, branding.companyDisplayName, branding.companyName]);
  const previewWidth = device === 'desktop' ? 1200 : device === 'tablet' ? 768 : 390;

  const load = async () => { setLoading(true); try { const next = await api<HomepageBuilderResponse>('/api/homepage-builder'); setData(next); setDraft({ ...emptyDraft, ...next.draft, sections: normalizeSections(next.draft?.sections) }); setSelectedId(next.draft?.sections?.[0]?.id || ''); } catch (error) { setStatus(error instanceof Error ? error.message : 'Unable to load builder'); } finally { setLoading(false); } };
  useEffect(() => { if (!initialData) load(); loadMedia(); }, []);
  const loadMedia = async () => { api<{ ok: boolean; media: MediaAsset[] }>('/api/media?visibility=public').then((p) => setMedia(p.media || [])).catch(() => undefined); };
  const commit = (producer: (current: HomepageDraft) => HomepageDraft, message = 'Updated draft') => { if (!canManage) return; setHistory((h) => [...h.slice(-30), draft]); setFuture([]); const next = producer(draft); setDraft({ ...next, sections: normalizeSections(next.sections).map((s, order) => ({ ...s, order })) }); setStatus(message); };
  const updateSection = (id: string, patch: Partial<HomepageSection>, message = 'Section updated') => commit((current) => ({ ...current, sections: current.sections.map((s) => s.id === id ? { ...s, ...patch, content: { ...s.content, ...(patch.content || {}) }, styles: { ...s.styles, ...(patch.styles || {}) }, visibility: { ...s.visibility, ...(patch.visibility || {}) }, advanced: { ...s.advanced, ...(patch.advanced || {}) }, animation: { ...s.animation, ...(patch.animation || {}) }, updatedAt: new Date().toISOString() } : s) }), message);
  const addSection = (typeOrSection: HomepageSectionType | HomepageSection) => { const section = typeof typeOrSection === 'string' ? makeSection(typeOrSection) : makeSection(typeOrSection.type, { ...typeOrSection, id: crypto.randomUUID(), createdAt: new Date().toISOString() }); commit((current) => ({ ...current, sections: [...current.sections, { ...section, order: current.sections.length }] }), `Added ${section.title}`); setSelectedId(section.id); };
  const duplicate = (section: HomepageSection) => addSection({ ...section, id: crypto.randomUUID(), title: `${section.title} copy` });
  const remove = (id: string) => commit((current) => ({ ...current, sections: current.sections.filter((s) => s.id !== id) }), 'Section deleted');
  const move = (id: string, dir: -1 | 1) => reorder(id, Math.max(0, normalizeSections(draft.sections).findIndex((s) => s.id === id) + dir));
  const reorder = (id: string, targetIndex: number) => commit((current) => { const next = normalizeSections(current.sections); const from = next.findIndex((s) => s.id === id); if (from < 0) return current; const [item] = next.splice(from, 1); next.splice(targetIndex, 0, item); return { ...current, sections: next }; }, 'Sections reordered');
  const undo = () => { const prev = history.at(-1); if (!prev) return; setFuture((f) => [draft, ...f]); setHistory((h) => h.slice(0, -1)); setDraft(prev); setStatus('Undo applied'); };
  const redo = () => { const next = future[0]; if (!next) return; setHistory((h) => [...h, draft]); setFuture((f) => f.slice(1)); setDraft(next); setStatus('Redo applied'); };
  const save = async () => { setStatus('Saving draft…'); try { const next = await api<HomepageBuilderResponse>('/api/homepage-builder/draft', { method: 'POST', body: JSON.stringify(draft) }); setData(next); setStatus('Draft saved to database'); reload?.(); } catch (e) { setStatus(e instanceof Error ? e.message : 'Save failed'); } };
  const publish = async () => { if (validation.critical.length) { setStatus('Fix critical validation issues before publishing.'); return; } setStatus('Publishing…'); try { const next = await api<HomepageBuilderResponse>('/api/homepage-builder/publish', { method: 'POST', body: JSON.stringify(draft) }); setData(next); setStatus('Published live homepage'); reload?.(); } catch (e) { setStatus(e instanceof Error ? e.message : 'Publish failed'); } };
  const restore = async (id: string) => { if (!confirm('Restore this version to the draft? It will not publish automatically.')) return; const next = await api<HomepageBuilderResponse>(`/api/homepage-builder/versions/${id}/restore`, { method: 'POST' }); setData(next); setDraft(next.draft); setStatus('Version restored to draft'); };
  const createBackup = async (name = 'Backup before preset replacement') => api('/api/homepage/backups', { method: 'POST', body: JSON.stringify({ ...draft, name }) });
  const applyTemplate = async (template: HomepageDraft, name: string) => { if (!confirm(`This will replace your current homepage sections. You can save a backup first.\n\nApply ${name}?`)) return; try { await createBackup(`Backup before ${name}`); commit(() => ({ ...template, globalStyles: { ...template.globalStyles, design: draft.globalStyles.design, background: draft.globalStyles.background } }), `${name} template applied; backup saved`); setSelectedId(template.sections[0]?.id || ''); setPresetBrowserOpen(false); } catch (e) { setStatus('Could not apply preset. Please try again.'); } };
  const matchSelectedToTheme = () => { if (!selected) return; updateSection(selected.id, matchSectionToTheme(selected), 'Selected section matched to site style'); };
  const matchAllToTheme = () => commit((current) => { const result = matchAllSectionsToTheme(current.sections); setStatus(`${result.changed.length} sections matched to the active theme`); return { ...current, sections: result.sections }; }, 'Matched all non-custom sections to theme');
  const upload = async (fileList: FileList | null) => { const file = fileList?.[0]; if (!file) return; const dataUrl = await new Promise<string>((resolve) => { const reader = new FileReader(); reader.onload = () => resolve(String(reader.result)); reader.readAsDataURL(file); }); await api('/api/media/upload', { method: 'POST', body: JSON.stringify({ fileName: file.name, mimeType: file.type, dataUrl, visibility: 'public' }) }); loadMedia(); };
  if (loading) return <section className="card settings-panel"><LoadingState title="Loading advanced homepage builder" lines={4}/></section>;

  return <section className="homepage-builder-shell">
    <div className="builder-toolbar"><Link href="/dashboard" className="button secondary small"><ArrowLeft size={16}/> Back to dashboard</Link><strong className="builder-page-name">Homepage</strong><Badge tone={data?.published ? 'success' : 'warning'}>{data?.published ? 'Published version exists' : 'No published version'}</Badge><span className="builder-status">{status}</span><button onClick={undo} disabled={!history.length}><Undo2 size={16}/> Undo</button><button onClick={redo} disabled={!future.length}><Redo2 size={16}/> Redo</button><button onClick={() => setDevice('desktop')} className={device === 'desktop' ? 'active' : ''}><Monitor size={16}/></button><button onClick={() => setDevice('tablet')} className={device === 'tablet' ? 'active' : ''}><Tablet size={16}/></button><button onClick={() => setDevice('mobile')} className={device === 'mobile' ? 'active' : ''}><Smartphone size={16}/></button><button onClick={() => window.open('/', '_blank')}><Eye size={16}/> Preview</button><button onClick={() => setPresetBrowserOpen(true)}><Layers size={16}/> Preset Browser</button><button disabled={!canManage} onClick={matchAllToTheme}><Palette size={16}/> Match All Sections To Theme</button><Button variant="secondary" disabled={!canManage} onClick={save}><Save size={16}/> Save Draft</Button><Button disabled={!canManage || validation.critical.length > 0} onClick={publish}><Send size={16}/> Publish</Button></div>
    <div className="builder-workspace">
      <aside className={`builder-left ${leftCollapsed ? 'collapsed' : ''}`}><button className="builder-collapse-toggle" onClick={() => { const next = !leftCollapsed; setLeftCollapsed(next); localStorage.setItem('homepageBuilderLeftCollapsed', String(next)); }}>{leftCollapsed ? '›' : '‹ Collapse'}</button><div className="builder-tabs"><button title="Add Sections" className={panel === 'sections' ? 'active' : ''} onClick={() => setPanel('sections')}><Library size={16}/><span>Add Sections</span></button><button title="Presets" className={panel === 'templates' ? 'active' : ''} onClick={() => { setPanel('templates'); setPresetBrowserOpen(true); }}><Layers size={16}/><span>Presets</span></button><button title="Pages/Sections" className={panel === 'pages' ? 'active' : ''} onClick={() => setPanel('pages')}><GripVertical size={16}/><span>Pages/Sections</span></button><button title="Theme/Layout" className={panel === 'theme' ? 'active' : ''} onClick={() => setPanel('theme')}><Palette size={16}/><span>Theme/Layout</span></button><button title="Animations" className={panel === 'animations' ? 'active' : ''} onClick={() => setPanel('animations')}><Redo2 size={16}/><span>Animations</span></button><button title="Global" className={panel === 'global' ? 'active' : ''} onClick={() => setPanel('global')}><Settings size={16}/><span>Global</span></button><button title="Media" className={panel === 'media' ? 'active' : ''} onClick={() => setPanel('media')}><Image size={16}/><span>Media</span></button></div>
        {panel === 'sections' && <div className="builder-panel-scroll premium-section-library"><h3>Premium Section Library</h3><p className="notice">Search contractor-ready blocks by category or conversion goal. Every preset inherits the active homepage theme by default.</p><label className="library-search"><Search size={15}/><input value={sectionSearch} onChange={(e) => setSectionSearch(e.target.value)} placeholder="Search heroes, emergency, reviews, financing…"/></label><div className="library-filter-strip" aria-label="Section categories">{libraryCategories.map((category) => <button key={category} className={sectionCategory === category ? 'active' : ''} onClick={() => setSectionCategory(category)}>{category}</button>)}</div><label>Filter by goal<select value={sectionGoal} onChange={(e) => setSectionGoal(e.target.value)}><option>All</option>{libraryGoals.filter((goal) => goal !== 'All').map((goal) => <option key={goal}>{goal}</option>)}</select></label><label>Premium filter<select value={sectionFilter} onChange={(e) => setSectionFilter(e.target.value)}>{premiumFilters.map((filter) => <option key={filter}>{filter}</option>)}</select></label><div className="library-result-count">{filteredLibrary.length} premium presets available</div>{Object.entries(groupBy(filteredLibrary, 'group')).map(([group, rows]) => <div key={group} className="library-group"><p className="eyebrow">{group}</p>{rows.map((preset) => <article className="preset-card premium-preset-card" key={preset.id} draggable onDragStart={() => setDragId(preset.id)} onDragEnd={() => setDragId('')}><LibraryThumbnail entry={preset}/><div className="preset-copy"><div className="preset-title-row"><strong>{preset.name}</strong><Badge>{preset.goal}</Badge></div><p>{preset.description}</p><small><b>Best for:</b> {preset.recommendedUseCase}</small><div className="preset-tags">{preset.tags.slice(0, 4).map((tag) => <span key={tag}>{tag}</span>)}</div><div className="preset-variants">{preset.variants.slice(0, 4).map((variant) => <span key={variant}>{variant}</span>)}</div></div><div className="preset-actions"><Button variant="secondary" onClick={() => setPreviewPreset(preset)}><Eye size={14}/> Preview</Button><Button onClick={() => addSection(preset.section)}><Plus size={14}/> Add</Button></div></article>)}</div>)}{!filteredLibrary.length && <EmptyState title="No presets match" description="Try a different search, category, or goal filter."/>}<details><summary>Basic section types</summary><div className="section-type-grid">{(Object.keys(sectionTypeLabels) as HomepageSectionType[]).map((type) => <button key={type} onClick={() => addSection(type)}><Plus size={14}/>{sectionTypeLabels[type]}</button>)}</div></details></div>}
        {panel === 'templates' && <div className="builder-panel-scroll"><h3>Preset Browser</h3><p className="notice">Open the full browser for large realistic previews, categories, and backup-safe apply options.</p><Button onClick={() => setPresetBrowserOpen(true)}>Browse premium presets</Button></div>}
        {panel === 'pages' && <div className="builder-panel-scroll"><h3>Pages / Sections</h3><p className="notice">Reorder, hide, duplicate, or delete sections from the rail below the canvas.</p>{normalizeSections(draft.sections).map((section) => <button key={section.id} onClick={() => setSelectedId(section.id)}>{section.title}</button>)}</div>}
        {panel === 'theme' && <GlobalEditor draft={draft} disabled={!canManage} update={(patch) => commit((current) => ({ ...current, ...patch }), 'Theme/layout settings updated')}/>}
        {panel === 'animations' && <div className="builder-panel-scroll"><h3>Animations</h3><p className="notice">Global animation defaults respect prefers-reduced-motion and reduce on mobile.</p><Range label="Default spacing rhythm" value={draft.globalStyles.sectionSpacingDefault || 88} min={48} max={140} disabled={!canManage} onChange={(v) => commit((current) => ({ ...current, globalStyles: { ...current.globalStyles, sectionSpacingDefault: v } }), 'Animation/layout rhythm updated')}/></div>}
        {panel === 'global' && <GlobalEditor draft={draft} disabled={!canManage} update={(patch) => commit((current) => ({ ...current, ...patch }), 'Global settings updated')}/>}        
        {panel === 'media' && <div className="builder-panel-scroll"><h3>Media Library</h3><label className="upload-chip"><Upload size={16}/> Upload public image<input hidden type="file" accept="image/*" onChange={(e) => upload(e.target.files)}/></label><p className="muted">Images on the homepage must be public. Private selections can be made public for homepage use.</p>{media.map((item) => <article className="media-picker-card" key={item.id}><div className="media-thumb">{item.url ? <img src={item.url} alt={item.altText || item.fileName}/> : <Image/>}</div><div><strong>{item.fileName}</strong><p>{item.visibility}</p>{selected && <Button variant="secondary" onClick={() => updateSection(selected.id, { content: { image: { id: item.id, url: item.url || `/api/media/${item.id}`, alt: item.altText || item.fileName, visibility: item.visibility } } })}>Set section image</Button>}</div></article>)}</div>}
      </aside>
      <main className="builder-canvas"><div className="preview-ruler"><span>{device} preview · {previewWidth}px</span><span>{draft.sections.length} sections</span></div><div className="preview-frame" style={{ maxWidth: previewWidth }} onDragOver={(e) => e.preventDefault()} onDrop={() => { const preset = library.find((p) => p.id === dragId); if (preset) addSection(preset.section); }}><HomepageRenderer draft={draft} editable selectedId={selectedId} onSelect={setSelectedId} onTextChange={(id, key, value) => updateSection(id, { content: { [key]: value } }, 'Inline text edited')} device={device}/></div><SectionRail sections={normalizeSections(draft.sections)} selectedId={selectedId} select={setSelectedId} move={move} remove={remove} duplicate={duplicate} toggle={(s) => updateSection(s.id, { enabled: !s.enabled }, s.enabled ? 'Section hidden' : 'Section shown')} reorder={reorder}/></main>
      <aside className={`builder-right ${rightCollapsed ? 'collapsed' : ''}`}><button className="builder-collapse-toggle" onClick={() => setRightCollapsed(!rightCollapsed)}>{rightCollapsed ? 'Open settings' : 'Collapse settings'}</button>{!rightCollapsed && <><RightEditor section={selected} disabled={!canManage} update={updateSection} media={media} matchSiteStyle={matchSelectedToTheme}/><ValidationDrawer validation={validation}/><VersionDrawer versions={data?.versions || []} restore={restore}/><AnalyticsPlaceholder/></>}</aside>
    </div>
    {presetBrowserOpen && <PresetBrowser templates={templates} draft={draft} device={device} canManage={canManage} applyTemplate={applyTemplate} onClose={() => setPresetBrowserOpen(false)}/>}
    {previewPreset && <div className="section-preview-modal" role="dialog" aria-modal="true"><div className="section-preview-card"><div className="section-preview-head"><div><p className="eyebrow">{previewPreset.category} · {previewPreset.goal}</p><h3>{previewPreset.name}</h3><p>{previewPreset.description}</p></div><button onClick={() => setPreviewPreset(null)}>×</button></div><HomepageRenderer draft={{ ...draft, sections: [previewPreset.section] }} device={device}/><div className="section-preview-actions"><span>{previewPreset.tags.join(' • ')}</span><Button variant="secondary" onClick={() => setPreviewPreset(null)}>Close</Button><Button onClick={() => { addSection(previewPreset.section); setPreviewPreset(null); }}>Add this section</Button></div></div></div>}
  </section>;
}


function PresetBrowser({ templates, draft, device, canManage, applyTemplate, onClose }: { templates: ReturnType<typeof pageTemplates>; draft: HomepageDraft; device: Device; canManage: boolean; applyTemplate: (template: HomepageDraft, name: string) => Promise<void>; onClose: () => void }) {
  const [query, setQuery] = useState('');
  const [category, setCategory] = useState('Premium Contractor');
  const [selected, setSelected] = useState(templates[0]);
  const categories = ['Premium Contractor','HVAC','Residential','Commercial','Emergency','Luxury','Minimal','Local Service'];
  const filtered = templates.filter((template) => [template.name, template.description, category].join(' ').toLowerCase().includes(query.toLowerCase()) || !query);
  return <div className="preset-browser-modal" role="dialog" aria-modal="true"><div className="preset-browser"><div className="preset-browser-head"><div><p className="eyebrow">Premium layout presets</p><h2>Choose a realistic homepage preset</h2><p>Presets replace layout sections only. Branding colors, active theme tokens, and typography stay intact.</p></div><button onClick={onClose}>×</button></div><div className="preset-browser-tools"><input value={query} onChange={(e) => setQuery(e.target.value)} placeholder="Search presets by industry or use case…"/><div>{categories.map((cat) => <button key={cat} className={category===cat?'active':''} onClick={() => setCategory(cat)}>{cat}</button>)}</div></div><div className="preset-browser-grid"><div className="preset-browser-list">{filtered.map((template) => <button key={template.id} className={selected?.id===template.id?'active':''} onClick={() => setSelected(template)}><HomepageRenderer draft={{ ...template.draft, globalStyles: { ...template.draft.globalStyles, design: draft.globalStyles.design, background: draft.globalStyles.background } }} device="mobile"/><strong>{template.name}</strong><span>{template.draft.sections.length} sections · Animation ready · Mobile quality high</span></button>)}</div>{selected && <div className="preset-detail-view"><HomepageRenderer draft={{ ...selected.draft, globalStyles: { ...selected.draft.globalStyles, design: draft.globalStyles.design, background: draft.globalStyles.background } }} device={device}/><h3>{selected.name}</h3><p>{selected.description}</p><div className="preset-detail-meta"><Badge>Best for: {category}</Badge><Badge>{selected.draft.sections.length} included sections</Badge><Badge>Animation: balanced</Badge><Badge>Setup effort: low</Badge></div><p className="notice">This will replace your current homepage sections. A backup is saved before applying.</p><div className="button-row"><Button disabled={!canManage} onClick={() => applyTemplate(selected.draft, selected.name)}>Apply Preset</Button><Button variant="secondary" disabled={!canManage} onClick={() => applyTemplate({ ...draft, sections: selected.draft.sections }, `${selected.name} sections only`)}>Apply Sections Only</Button><Button variant="secondary" onClick={onClose}>Cancel</Button></div></div>}</div></div></div>;
}

function SectionRail({ sections, selectedId, select, move, remove, duplicate, toggle, reorder }: { sections: HomepageSection[]; selectedId: string; select: (id: string) => void; move: (id: string, dir: -1 | 1) => void; remove: (id: string) => void; duplicate: (s: HomepageSection) => void; toggle: (s: HomepageSection) => void; reorder: (id: string, target: number) => void }) { const [dragging, setDragging] = useState(''); return <div className="section-rail">{sections.map((section, index) => <article key={section.id} className={selectedId === section.id ? 'selected' : ''} draggable onDragStart={() => setDragging(section.id)} onDragOver={(e) => e.preventDefault()} onDrop={() => dragging && reorder(dragging, index)} onClick={() => select(section.id)}><GripVertical size={16}/><span>{section.title}</span><Badge tone={section.enabled ? 'success' : 'warning'}>{section.enabled ? 'Shown' : 'Hidden'}</Badge><button onClick={(e) => { e.stopPropagation(); move(section.id, -1); }}>↑</button><button onClick={(e) => { e.stopPropagation(); move(section.id, 1); }}>↓</button><button onClick={(e) => { e.stopPropagation(); toggle(section); }}>{section.enabled ? 'Hide' : 'Show'}</button><button onClick={(e) => { e.stopPropagation(); duplicate(section); }}><Copy size={14}/></button><button onClick={(e) => { e.stopPropagation(); remove(section.id); }}><Trash2 size={14}/></button></article>)}</div>; }
function RightEditor({ section, disabled, update, media, matchSiteStyle }: { section: HomepageSection | null; disabled: boolean; update: (id: string, patch: Partial<HomepageSection>, message?: string) => void; media: MediaAsset[]; matchSiteStyle: () => void }) { if (!section) return <div className="builder-inspector"><EmptyState title="Select a section" description="Click a section in the canvas or rail to edit content, styles, links, visibility, and advanced settings."/></div>; const c = section.content; const s = section.styles; const setContent = (patch: any) => update(section.id, { content: patch }); const setStyle = (patch: any) => update(section.id, { styles: patch }); const setVisibility = (patch: any) => update(section.id, { visibility: patch }); const setAdvanced = (patch: any) => update(section.id, { advanced: patch }); const setAnimation = (patch: any) => update(section.id, { animation: patch }, 'Animation updated'); const a = section.animation || {}; return <div className="builder-inspector"><h3>Selected section settings</h3><Badge>{sectionTypeLabels[section.type]}</Badge><Button variant="secondary" disabled={disabled} onClick={matchSiteStyle}><Palette size={14}/> Match Site Style</Button><label>Internal label<input disabled={disabled} value={section.title} onChange={(e) => update(section.id, { title: e.target.value })}/></label><details open><summary>Content fields</summary><label>Heading<input disabled={disabled} value={c.heading || ''} onChange={(e) => setContent({ heading: e.target.value })}/></label><label>Subheading<input disabled={disabled} value={c.subheading || ''} onChange={(e) => setContent({ subheading: e.target.value })}/></label><label>Body<textarea disabled={disabled} value={c.body || c.richText || ''} onChange={(e) => setContent(section.type === 'custom-rich-text' ? { richText: e.target.value } : { body: e.target.value })}/></label><ButtonsEditor buttons={c.buttons || []} disabled={disabled} update={(buttons) => setContent({ buttons })}/><ItemsEditor items={c.items || []} disabled={disabled} update={(items) => setContent({ items })}/><label>Image URL<input disabled={disabled} value={c.image?.url || ''} onChange={(e) => setContent({ image: { ...(c.image || {}), url: e.target.value } })}/></label><select disabled={disabled} onChange={(e) => { const m = media.find((x) => x.id === e.target.value); if (m) setContent({ image: { id: m.id, url: m.url || `/api/media/${m.id}`, alt: m.altText || m.fileName, visibility: m.visibility } as HomepageMedia }); }}><option value="">Pick public media…</option>{media.map((m) => <option key={m.id} value={m.id}>{m.fileName}</option>)}</select>{c.image?.visibility === 'private' && <Button variant="secondary">Make public for homepage</Button>}</details><details open><summary>Style controls</summary><label>Style mode<select disabled={disabled} value={s.styleMode || 'inherit'} onChange={(e) => setStyle(sectionStyleModePatch(e.target.value))}><option value="inherit">Inherit Theme</option><option value="alternate">Theme Alternate</option><option value="primary-accent">Primary Feature</option><option value="accent-feature">Accent Feature</option><option value="dark-contrast">Dark Contrast</option><option value="light-contrast">Light Contrast</option><option value="custom">Custom</option></select></label>{(s.styleMode || 'inherit') !== 'custom' && <p className="notice">Colors are inherited from active theme tokens. Choose Custom to override this section only.</p>}{(s.styleMode || 'inherit') === 'custom' && <>
<p className="notice">This section is overriding the global theme.</p>
<Button variant="secondary" disabled={disabled} onClick={() => setStyle(sectionStyleModePatch('inherit'))}>Reset to Theme Colors</Button><Color label="Background" value={s.backgroundColor} disabled={disabled} onChange={(v) => setStyle({ backgroundColor: v, background: v })}/><Color label="Text" value={s.textColor} disabled={disabled} onChange={(v) => setStyle({ textColor: v })}/><Color label="Accent" value={s.accentColor} disabled={disabled} onChange={(v) => setStyle({ accentColor: v })}/><Color label="Card background" value={s.cardBackground} disabled={disabled} onChange={(v) => setStyle({ cardBackground: v })}/><Color label="Border" value={s.borderColor} disabled={disabled} onChange={(v) => setStyle({ borderColor: v })}/></>}<label>Background image URL<input disabled={disabled} value={s.backgroundImage?.url || ''} onChange={(e) => setStyle({ backgroundImage: { ...(s.backgroundImage || {}), url: e.target.value } })}/></label><Range label="Overlay opacity" value={s.overlayOpacity || 0} min={0} max={90} disabled={disabled} onChange={(v) => setStyle({ overlayOpacity: v })}/><Range label="Spacing top" value={s.spacingTop || 0} min={0} max={180} disabled={disabled} onChange={(v) => setStyle({ spacingTop: v })}/><Range label="Spacing bottom" value={s.spacingBottom || 0} min={0} max={180} disabled={disabled} onChange={(v) => setStyle({ spacingBottom: v })}/><Range label="Border radius" value={s.borderRadius || 0} min={0} max={48} disabled={disabled} onChange={(v) => setStyle({ borderRadius: v })}/><label>Layout variant<select disabled={disabled} value={s.layoutVariant || 'standard'} onChange={(e) => setStyle({ layoutVariant: e.target.value })}>{sectionVariantOptions(section.type).map((variant) => <option key={variant} value={variant}>{variant.replace(/-/g, ' ')}</option>)}</select></label><label>Card style<select disabled={disabled} value={s.cardStyle || 'elevated'} onChange={(e) => setStyle({ cardStyle: e.target.value })}>{['flat','bordered','elevated','glass'].map((x) => <option key={x} value={x}>{x}</option>)}</select></label><Range label="Content max width" value={s.maxWidth || 1180} min={720} max={1440} disabled={disabled} onChange={(v) => setStyle({ maxWidth: v })}/><label>Alignment<select disabled={disabled} value={s.alignment || 'left'} onChange={(e) => setStyle({ alignment: e.target.value })}><option>left</option><option>center</option><option>right</option></select></label><Range label="Columns" value={s.columns || 1} min={1} max={4} disabled={disabled} onChange={(v) => setStyle({ columns: v })}/><label className="check"><input disabled={disabled} type="checkbox" checked={Boolean(s.cardShadow)} onChange={(e) => setStyle({ cardShadow: e.target.checked })}/> Card shadow</label></details><details open><summary>Animation controls</summary><p className="notice">Animations use theme tokens, transform/opacity CSS, mobile-safe defaults, and automatically respect reduced motion.</p><label>Animation<select disabled={disabled} value={a.style || 'fade-up'} onChange={(e) => setAnimation({ style: e.target.value })}>{['none','fade-up','slide-left','slide-right','scale-in','stagger-cards','marquee','floating','pulse','counter','reveal-line','carousel'].map((x) => <option key={x} value={x}>{x.replace(/-/g, ' ')}</option>)}</select></label><label>Speed<select disabled={disabled} value={a.speed || 'normal'} onChange={(e) => setAnimation({ speed: e.target.value })}>{['slow','normal','fast'].map((x) => <option key={x}>{x}</option>)}</select></label><label>Intensity<select disabled={disabled} value={a.intensity || 'subtle'} onChange={(e) => setAnimation({ intensity: e.target.value })}>{['subtle','medium','strong'].map((x) => <option key={x}>{x}</option>)}</select></label><label>Trigger<select disabled={disabled} value={a.trigger || 'on-scroll'} onChange={(e) => setAnimation({ trigger: e.target.value })}>{['on-load','on-scroll','on-hover','continuous'].map((x) => <option key={x} value={x}>{x.replace(/-/g, ' ')}</option>)}</select></label><label>Mobile behavior<select disabled={disabled} value={a.mobileBehavior || 'reduced'} onChange={(e) => setAnimation({ mobileBehavior: e.target.value })}>{['full','reduced','disabled'].map((x) => <option key={x}>{x}</option>)}</select></label></details><details open><summary>Visibility controls</summary>{(['desktop','tablet','mobile','public'] as const).map((key) => <label className="check" key={key}><input disabled={disabled} type="checkbox" checked={Boolean(section.visibility[key])} onChange={(e) => setVisibility({ [key]: e.target.checked })}/> Show on {key}</label>)}</details><details><summary>Advanced options</summary><label>Anchor ID<input disabled={disabled} value={section.advanced.anchorId || ''} onChange={(e) => setAdvanced({ anchorId: e.target.value })}/></label><label>CSS class<input disabled={disabled} value={section.advanced.cssClass || ''} onChange={(e) => setAdvanced({ cssClass: e.target.value })}/></label><label>SEO/internal label<input disabled={disabled} value={section.advanced.seoLabel || ''} onChange={(e) => setAdvanced({ seoLabel: e.target.value })}/></label></details></div>; }
function GlobalEditor({ draft, disabled, update }: { draft: HomepageDraft; disabled: boolean; update: (patch: Partial<HomepageDraft>) => void }) {
  const g = draft.globalStyles;
  const seo = draft.seo;
  const design = g.design || defaultGlobalStyles.design;
  const confirmDraft = () => confirm('This will update your draft homepage style. It will not affect the live homepage until you publish.');
  const applyPreset = (preset: keyof typeof designThemePresets) => {
    const nextDesign = { themePreset: preset, ...designThemePresets[preset] };
    update({ globalStyles: { ...g, design: nextDesign, background: nextDesign.colors.background, buttonStyle: nextDesign.buttons.style, cardRadius: parseInt(nextDesign.radius, 10) || g.cardRadius } });
  };
  const applyHomepagePreset = (presetId: keyof typeof homepageStylePresets, mode: 'layout' | 'order' | 'styleModes') => {
    if (!confirmDraft()) return;
    const preset = homepageStylePresets[presetId];
    const currentDesign = g.design || defaultGlobalStyles.design;
    const layoutOnlyGlobal = { ...g, ...preset.globalStyles, design: currentDesign, background: g.background || 'var(--site-background)', sectionDefaults: preset.sectionDefaults, homepageLayout: preset.homepageLayout };
    const shouldApplyStyles = mode === 'layout' || mode === 'styleModes';
    const orderPreference = preset.id === 'emergency-service'
      ? ['hero','emergency-banner','trust-badges','services-grid','stats-numbers','google-reviews','faq','call-to-action','request-estimate-form','contact-block']
      : preset.id === 'commercial-maintenance'
        ? ['hero','logo-brand-strip','service-detail-cards','process-steps','stats-numbers','project-showcase','request-estimate-form','contact-block']
        : ['hero','trust-badges','services-grid','why-choose-us','stats-numbers','project-showcase','before-after-gallery','google-reviews','process-steps','service-area','faq','team-section','call-to-action','request-estimate-form','contact-block'];
    const styledSections = shouldApplyStyles ? draft.sections.map((section) => {
      if (section.styles?.styleMode === 'custom') return section;
      return { ...section, styles: { ...section.styles, styleMode: preset.sectionDefaults.styleMode, layoutVariant: section.styles?.layoutVariant, columns: section.styles?.columns, cardStyle: preset.sectionDefaults.cardStyle, borderRadius: preset.sectionDefaults.borderRadius, spacingTop: preset.sectionDefaults.spacingTop, spacingBottom: preset.sectionDefaults.spacingBottom, cardShadow: preset.sectionDefaults.cardShadow } };
    }) : draft.sections;
    const nextSections = mode === 'order' ? [...styledSections].sort((a, b) => (orderPreference.indexOf(a.type) === -1 ? 99 : orderPreference.indexOf(a.type)) - (orderPreference.indexOf(b.type) === -1 ? 99 : orderPreference.indexOf(b.type))) : styledSections;
    update({ globalStyles: layoutOnlyGlobal as any, sections: nextSections });
  };
  return <div className="builder-panel-scroll"><h3>Homepage Layout Presets</h3><p className="notice">Layout presets change structure, spacing, section style, and content arrangement. Colors come from your active Theme/Branding settings.</p><div className="homepage-preset-grid">{Object.values(homepageStylePresets).map((preset) => <article className="preset-card" key={preset.id}><div><strong>{preset.name}</strong><p>{preset.description}</p><small className="muted">Layout only · uses active theme colors</small></div><div className="preset-actions"><Button variant="secondary" disabled={disabled} onClick={() => applyHomepagePreset(preset.id, 'layout')}>Apply Layout Only</Button><Button variant="secondary" disabled={disabled} onClick={() => applyHomepagePreset(preset.id, 'order')}>Apply Section Order</Button><Button disabled={disabled} onClick={() => applyHomepagePreset(preset.id, 'styleModes')}>Apply Section Style Modes</Button></div></article>)}</div><h3>Current Active Theme / Branding</h3><p className="notice">Theme/Branding is the single color source of truth. Homepage layout presets cannot apply colors.</p><Link href="/settings" className="button secondary small">Edit Theme Colors</Link><label>Apply scope<select disabled={true} value={design.scope} onChange={(e) => update({ globalStyles: { ...g, design: { ...design, scope: e.target.value as any } } })}><option value="entire-app">Entire app</option><option value="public">Public pages</option><option value="homepage">Homepage only</option></select></label><label>Theme color preset (read-only)<select disabled={true} value={design.themePreset} onChange={(e) => applyPreset(e.target.value as keyof typeof designThemePresets)}>{Object.keys(designThemePresets).map((preset) => <option key={preset} value={preset}>{preset.replace(/_/g, ' ')}</option>)}</select></label><label>Header style<select disabled={disabled} value={design.header.style} onChange={(e) => update({ globalStyles: { ...g, design: { ...design, header: { ...design.header, style: e.target.value as any } } } })}>{['solid','transparent','glass','centered'].map((x) => <option key={x} value={x}>{x}</option>)}</select></label><label>Button style<select disabled={disabled} value={design.buttons.style} onChange={(e) => update({ globalStyles: { ...g, buttonStyle: e.target.value as any, design: { ...design, buttons: { style: e.target.value as any } } } })}>{['rounded','pill','square','glass'].map((x) => <option key={x} value={x}>{x}</option>)}</select></label><label>Card style<select disabled={disabled} value={design.cards.style} onChange={(e) => update({ globalStyles: { ...g, design: { ...design, cards: { style: e.target.value as any } } } })}>{['flat','raised','glass','bordered'].map((x) => <option key={x} value={x}>{x}</option>)}</select></label><Color label="Primary color" value={design.colors.primary} disabled={true} onChange={(v) => update({ globalStyles: { ...g, design: { ...design, colors: { ...design.colors, primary: v } } } })}/><Color label="Secondary color" value={design.colors.secondary} disabled={true} onChange={(v) => update({ globalStyles: { ...g, design: { ...design, colors: { ...design.colors, secondary: v } } } })}/><Color label="Accent color" value={design.colors.accent} disabled={true} onChange={(v) => update({ globalStyles: { ...g, design: { ...design, colors: { ...design.colors, accent: v } } } })}/><Color label="Background color" value={design.colors.background} disabled={true} onChange={(v) => update({ globalStyles: { ...g, background: v, design: { ...design, colors: { ...design.colors, background: v }, background: { ...design.background, color: v } } } })}/><Color label="Card color" value={design.colors.card} disabled={true} onChange={(v) => update({ globalStyles: { ...g, design: { ...design, colors: { ...design.colors, card: v } } } })}/><Color label="Text color" value={design.colors.text} disabled={true} onChange={(v) => update({ globalStyles: { ...g, design: { ...design, colors: { ...design.colors, text: v } } } })}/><h3>Animation Settings</h3><p className="notice">Defaults apply to new animated sections. Reduced-motion preferences are respected by renderer CSS.</p><label className="check"><input disabled={disabled} type="checkbox" checked={g.animation.enabled} onChange={(e) => update({ globalStyles: { ...g, animation: { ...g.animation, enabled: e.target.checked } } })}/> Enable homepage animations</label><label>Default animation style<select disabled={disabled} value={g.animation.defaultStyle} onChange={(e) => update({ globalStyles: { ...g, animation: { ...g.animation, defaultStyle: e.target.value as any } } })}>{['none','fade-up','slide-left','slide-right','scale-in','stagger-cards','marquee','floating','pulse','counter','reveal-line','carousel'].map((x) => <option key={x} value={x}>{x.replace(/-/g, ' ')}</option>)}</select></label><label>Default animation intensity<select disabled={disabled} value={g.animation.defaultIntensity || 'subtle'} onChange={(e) => update({ globalStyles: { ...g, animation: { ...g.animation, defaultIntensity: e.target.value as any } } })}>{['subtle','medium','strong'].map((x) => <option key={x}>{x}</option>)}</select></label><label>Default animation speed<select disabled={disabled} value={g.animation.defaultSpeed} onChange={(e) => update({ globalStyles: { ...g, animation: { ...g.animation, defaultSpeed: e.target.value as any } } })}>{['slow','normal','fast'].map((x) => <option key={x}>{x}</option>)}</select></label><label className="check"><input disabled={disabled} type="checkbox" checked={g.animation.reduceOnMobile} onChange={(e) => update({ globalStyles: { ...g, animation: { ...g.animation, reduceOnMobile: e.target.checked } } })}/> Reduce animations on mobile</label><label className="check"><input disabled={disabled} type="checkbox" checked={g.animation.disableContinuous} onChange={(e) => update({ globalStyles: { ...g, animation: { ...g.animation, disableContinuous: e.target.checked } } })}/> Disable continuous animations</label><label className="check"><input disabled={disabled} type="checkbox" checked={g.animation.respectReducedMotion} onChange={(e) => update({ globalStyles: { ...g, animation: { ...g.animation, respectReducedMotion: e.target.checked } } })}/> Respect reduced motion setting</label><h3>SEO</h3><label>SEO title<input disabled={disabled} value={seo.title || ''} onChange={(e) => update({ seo: { ...seo, title: e.target.value } })}/></label><label>Meta description<textarea disabled={disabled} value={seo.description || ''} onChange={(e) => update({ seo: { ...seo, description: e.target.value } })}/></label><Range label="Max page width" value={g.maxPageWidth} min={760} max={1600} disabled={disabled} onChange={(v) => update({ globalStyles: { ...g, maxPageWidth: v } })}/><Range label="Default spacing" value={g.sectionSpacingDefault} min={32} max={160} disabled={disabled} onChange={(v) => update({ globalStyles: { ...g, sectionSpacingDefault: v } })}/></div>;
}
function sectionStyleModePatch(mode: string) {
  if (mode === 'alternate') return { styleMode: 'alternate', backgroundColor: 'var(--surface-section-alt)', background: 'var(--surface-section-alt)', textColor: 'var(--site-text)', accentColor: 'var(--site-primary)', cardBackground: 'var(--surface-card)', borderColor: 'var(--site-border)' };
  if (mode === 'primary-accent') return { styleMode: 'primary-accent', backgroundColor: 'var(--site-primary)', background: 'var(--site-primary)', textColor: 'var(--site-primary-contrast)', accentColor: 'var(--site-accent)', cardBackground: 'var(--surface-glass)', borderColor: 'var(--site-border)' };
  if (mode === 'accent-feature') return { styleMode: 'accent-feature', backgroundColor: 'var(--site-accent)', background: 'var(--site-accent)', textColor: 'var(--site-accent-contrast)', accentColor: 'var(--site-primary)', cardBackground: 'var(--surface-glass)', borderColor: 'var(--site-border)' };
  if (mode === 'dark-contrast') return { styleMode: 'dark-contrast', backgroundColor: 'var(--surface-dark)', background: 'var(--surface-dark)', textColor: 'var(--surface-dark-text)', accentColor: 'var(--site-accent)', cardBackground: 'var(--surface-glass)', borderColor: 'var(--site-border)' };
  if (mode === 'light-contrast') return { styleMode: 'light-contrast', backgroundColor: 'var(--surface-light)', background: 'var(--surface-light)', textColor: 'var(--surface-light-text)', accentColor: 'var(--site-primary)', cardBackground: 'var(--surface-card)', borderColor: 'var(--site-border)' };
  if (mode === 'custom') return { styleMode: 'custom' };
  return { styleMode: 'inherit', backgroundColor: 'var(--surface-section)', background: 'var(--surface-section)', textColor: 'var(--site-text)', accentColor: 'var(--site-primary)', cardBackground: 'var(--surface-card)', borderColor: 'var(--site-border)' };
}
function ButtonsEditor({ buttons, disabled, update }: { buttons: any[]; disabled: boolean; update: (buttons: any[]) => void }) { return <div><strong>Buttons / links</strong>{buttons.map((b, i) => <div className="mini-grid" key={b.id}><input disabled={disabled} value={b.label || ''} onChange={(e) => update(buttons.map((x) => x.id === b.id ? { ...x, label: e.target.value } : x))}/><input disabled={disabled} value={b.href || ''} onChange={(e) => update(buttons.map((x) => x.id === b.id ? { ...x, href: e.target.value } : x))}/><button disabled={disabled} onClick={() => update(buttons.filter((_, n) => n !== i))}>×</button></div>)}<Button variant="secondary" disabled={disabled} onClick={() => update([...buttons, { id: crypto.randomUUID(), label: 'Request Estimate', href: '/request-estimate', style: 'primary' }])}>Add button</Button></div>; }
function ItemsEditor({ items, disabled, update }: { items: HomepageItem[]; disabled: boolean; update: (items: HomepageItem[]) => void }) { return <div><strong>Cards / list items</strong>{items.map((item, i) => <div className="mini-grid" key={item.id}><input disabled={disabled} value={item.title || ''} onChange={(e) => update(items.map((x) => x.id === item.id ? { ...x, title: e.target.value } : x))}/><input disabled={disabled} value={item.text || ''} onChange={(e) => update(items.map((x) => x.id === item.id ? { ...x, text: e.target.value } : x))}/><button disabled={disabled} onClick={() => update(items.filter((_, n) => n !== i))}>×</button></div>)}<Button variant="secondary" disabled={disabled} onClick={() => update([...items, { id: crypto.randomUUID(), title: 'Warranty-backed work', text: 'Describe a clear customer benefit, proof point, or next step.' }])}>Add card</Button></div>; }
function sectionVariantOptions(type: HomepageSectionType) {
  const shared = ['standard','split-image','centered','cards','compact','feature','banner'];
  const map: Partial<Record<HomepageSectionType, string[]>> = {
    hero: ['standard','split-image','centered','emergency','video','map-cta','before-after-hero','trust-badges'],
    'services-grid': ['6-card-grid','3-card-simple','image-cards','icon-list','trade-cards','dark-premium-cards','commercial-services','residential-services'],
    'service-detail-cards': ['detail-cards','service-spotlight','commercial-services','residential-services','maintenance-plan','membership-plans'],
    'project-showcase': ['featured-slider','gallery-grid','case-study','recent-jobs','filtered-projects','photo-gallery'],
    'featured-projects': ['featured-slider','full-width-feature','carousel','grid'],
    'before-after-gallery': ['comparison','2-up','single-feature','grid'],
    testimonials: ['review-grid','featured-testimonial','video-testimonial','review-cta-split'],
    'google-reviews': ['google-carousel','rating-strip','rating-summary','review-grid'],
    'process-steps': ['4-step-timeline','horizontal-process','vertical-mobile-process','estimate-workflow','what-happens-next'],
    faq: ['faq-accordion','faq-two-column','emergency-faq','pricing-faq','warranty-faq'],
    'service-area': ['city-grid','zip-list','county-service-area','map-embed','neighborhood-tags','local-seo-block'],
    'call-to-action': ['estimate-cta','call-now-cta','sticky-mobile-cta','offer-banner','seasonal-promo'],
    'emergency-banner': ['emergency-alert','emergency-cta','after-hours'],
    'financing-banner': ['financing-cta','financing-calculator','payment-options'],
    'custom-image-text': ['image-text-split','full-width-image-banner','video-embed'],
  };
  return Array.from(new Set([...(map[type] || shared), ...shared]));
}
function LibraryThumbnail({ entry }: { entry: HomepageSectionLibraryEntry }) {
  const cells = entry.thumbnail === 'hero-split' ? ['wide','media','line','line short'] : entry.thumbnail === 'hero-centered' ? ['line center','line center short','pill center','pill center'] : entry.thumbnail === 'banner' || entry.thumbnail === 'offer' ? ['banner','line','pill','pill'] : entry.thumbnail === 'gallery' ? ['photo','photo','photo','photo'] : entry.thumbnail === 'reviews' ? ['stars','quote','quote','stars'] : entry.thumbnail === 'timeline' ? ['dot','dot','dot','dot'] : entry.thumbnail === 'map' ? ['map','pin','pin','line'] : entry.thumbnail === 'faq' ? ['faq','faq','faq'] : entry.thumbnail === 'form' ? ['input','input','button'] : entry.thumbnail === 'logos' ? ['logo','logo','logo','logo'] : ['card','card','card'];
  return <div className={`library-thumb thumb-${entry.thumbnail}`} aria-hidden="true"><b>{entry.category.replace(' Sections', '')}</b>{cells.map((cell, index) => <span key={index} className={cell}/>)}<em>{entry.tags[0] || 'Premium'}</em></div>;
}
function ValidationDrawer({ validation }: { validation: { critical: string[]; warnings: string[] } }) { return <details className="builder-drawer" open><summary>Validation</summary>{validation.critical.length === 0 && validation.warnings.length === 0 ? <Badge tone="success">Ready to publish</Badge> : null}{validation.critical.map((x) => <p className="error-text" key={x}>Critical: {x}</p>)}{validation.warnings.map((x) => <p className="muted" key={x}>Warning: {x}</p>)}</details>; }
function VersionDrawer({ versions, restore }: { versions: any[]; restore: (id: string) => void }) { return <details className="builder-drawer"><summary><History size={15}/> Version history</summary>{versions.length ? versions.map((v) => <article key={v.id} className="version-row"><strong>{v.name || v.status}</strong><small>{v.status} · {new Date(v.publishedAt || v.createdAt).toLocaleString()}</small><Button variant="secondary" onClick={() => restore(v.id)}>Restore</Button></article>) : <p className="muted">No versions yet.</p>}</details>; }
function AnalyticsPlaceholder() { return <details className="builder-drawer"><summary>Homepage analytics</summary>{['views','request estimate clicks','CTA clicks','form starts','form submissions'].map((x) => <p key={x}><Badge>0</Badge> {x}</p>)}</details>; }
function Range({ label, value, min, max, disabled, onChange }: { label: string; value: number; min: number; max: number; disabled: boolean; onChange: (v: number) => void }) { return <label>{label}<input disabled={disabled} type="range" min={min} max={max} value={value} onChange={(e) => onChange(Number(e.target.value))}/><small>{value}</small></label>; }
function Color({ label, value = '#ffffff', disabled, onChange }: { label: string; value?: string; disabled: boolean; onChange: (v: string) => void }) { return <label>{label}<span className="color-row"><input disabled={disabled} type="color" value={/^#[0-9a-f]{6}$/i.test(value) ? value : '#ffffff'} onChange={(e) => onChange(e.target.value)}/><input disabled={disabled} value={value} onChange={(e) => onChange(e.target.value)}/></span></label>; }
function groupBy<T extends Record<string, any>>(rows: T[], key: keyof T) { return rows.reduce<Record<string, T[]>>((acc, row) => ({ ...acc, [row[key]]: [...(acc[row[key]] || []), row] }), {}); }
